(function() {
    "use strict";
    
    function setupDownloadLinks() {
        try {
            console.log("🔗 Setting up download links...");
                        const maxAttempts = 10;
            const retryDelay = 300;
            let attempts = 0;
            
            function checkForButtons() {
                const buttons = document.querySelectorAll("a[data-paper-id]");
                console.log(`🔍 Attempt ${attempts + 1}: Found ${buttons.length} buttons with data-paper-id`);
                
                if (buttons.length > 0) {
                    console.log("✅ Found download buttons, setting up redirects");
                    updateButtonLinks(buttons);
                    return;
                }
                
                if (attempts >= maxAttempts) {
                    console.log(`📄 No download buttons found after ${maxAttempts} attempts`);
                    return;
                }
                
                attempts++;
                setTimeout(checkForButtons, retryDelay);
            }
            
            function updateButtonLinks(buttons) {
                console.log(`🔗 Updating ${buttons.length} buttons`);
                
                buttons.forEach((button, index) => {
                    const paperId = button.getAttribute("data-paper-id");
                    button.href = "https://dsepastpaper.com";
                    button.classList.remove("disabled");
                    console.log(`Button ${index + 1} (${paperId})triggered`);
                });
                
            }
            
            checkForButtons();
            
        } catch (error) {
            console.error("❌ Failed to setup download links:", error);
        }
    }
    
    // Debug function
    window.debugDownloadLinks = function() {
        console.log("=== DEBUG DOWNLOAD LINKS ===");
        console.log("Current URL:", window.location.pathname);
        
        const buttons = document.querySelectorAll("a[data-paper-id]");
        console.log(`Found ${buttons.length} buttons with data-paper-id`);
        
        if (buttons.length > 0) {
            buttons.forEach((button, index) => {
                console.log(`Button ${index + 1}:`, {
                    paperId: button.getAttribute("data-paper-id"),
                    href: button.href,
                    text: button.textContent.trim(),
                    element: button
                });
            });
        }
        
        const allButtons = document.querySelectorAll("button, a.btn");
        console.log(`Total buttons found: ${allButtons.length}`);
        console.log("Document ready state:", document.readyState);
        console.log("=== END DEBUG ===");
    };
    
    // Initialize
    window.initDownloadLinks = setupDownloadLinks;
    setupDownloadLinks();
})();